#!/usr/bin/env python3
"""Generated by superpower-adapter.

Section marker extraction for wiki documents.

Markers use HTML comments: <!-- wiki-section:section-id --> / <!-- /wiki-section:section-id -->
Section IDs are restricted to kebab-case: [a-z0-9][a-z0-9_-]*
"""

from __future__ import annotations

import re
from dataclasses import dataclass, field

SECTION_ID_PATTERN = r"[a-z0-9][a-z0-9_-]*"
DOCUMENT_OVERVIEW_LIMIT = 600
AUTO_GENERATED_INDEX_NOTICE = "Auto-generated from section markers. Do not edit manually."
OPEN_RE = re.compile(r"^<!-- wiki-section:(" + SECTION_ID_PATTERN + r") -->$")
CLOSE_RE = re.compile(r"^<!-- /wiki-section:(" + SECTION_ID_PATTERN + r") -->$")
FENCE_OPEN_RE = re.compile(r"^(`{3,}|~{3,})")

# Knowledge edges are only the explicit [[page#section]] form (a deliberate
# "this is a knowledge edge" signal). Plain markdown links like (path#anchor)
# are incidental prose and are NOT treated as section edges.
WIKILINK_RE = re.compile(r"\[\[([^\[\]]+)\]\]")
INLINE_CODE_RE = re.compile(r"`[^`]*`")

# Typed edges use an inline prefix: [[type: page#section]]. The colon must be
# followed by whitespace so a bare URL ([[http://...]]) or untyped link is not
# mistaken for a type. A bare [[ ]] (no recognized prefix) defaults to see-also.
KNOWN_EDGE_TYPES = ("see-also", "depends-on", "supersedes", "contradicts")
DEFAULT_EDGE_TYPE = "see-also"
EDGE_TYPE_RE = re.compile(r"^([a-z][a-z0-9-]*):\s+(.+)$")


@dataclass
class _SectionSpan:
    section_id: str
    start_line: int
    end_line: int | None = None
    children: list[_SectionSpan] = field(default_factory=list)


def _skip_fenced_blocks(lines: list[str]) -> set[int]:
    """Return set of line indices that are inside fenced code blocks."""
    inside: set[int] = set()
    fence_char: str | None = None
    fence_len: int = 0
    for i, line in enumerate(lines):
        stripped = line.strip()
        if fence_char is None:
            m = FENCE_OPEN_RE.match(stripped)
            if m:
                fence_char = m.group(1)[0]
                fence_len = len(m.group(1))
                inside.add(i)
        else:
            inside.add(i)
            if stripped.startswith(fence_char * fence_len) and stripped.rstrip(fence_char) == "":
                fence_char = None
                fence_len = 0
    return inside


def _parse_spans(text: str) -> tuple[list[_SectionSpan], list[str]]:
    """Parse all section spans from text, returning top-level spans and errors."""
    lines = text.splitlines()
    fenced = _skip_fenced_blocks(lines)
    errors: list[str] = []
    stack: list[_SectionSpan] = []
    top_level: list[_SectionSpan] = []

    for i, line in enumerate(lines):
        if i in fenced:
            continue
        stripped = line.strip()
        open_m = OPEN_RE.match(stripped)
        if open_m:
            span = _SectionSpan(section_id=open_m.group(1), start_line=i)
            if stack:
                stack[-1].children.append(span)
            else:
                top_level.append(span)
            stack.append(span)
            continue
        close_m = CLOSE_RE.match(stripped)
        if close_m:
            sid = close_m.group(1)
            if not stack:
                errors.append(f"Line {i + 1}: closing marker for '{sid}' without matching open")
            elif stack[-1].section_id != sid:
                errors.append(
                    f"Line {i + 1}: closing marker for '{sid}' but expected '{stack[-1].section_id}'"
                )
            else:
                stack[-1].end_line = i
                stack.pop()

    for span in stack:
        errors.append(f"Line {span.start_line + 1}: unclosed section '{span.section_id}'")

    return top_level, errors


def _collect_all(spans: list[_SectionSpan], lines: list[str]) -> dict[str, str]:
    """Recursively collect all sections (including nested) into a flat dict."""
    result: dict[str, str] = {}
    for span in spans:
        if span.end_line is None:
            continue
        content_lines = lines[span.start_line + 1 : span.end_line]
        result[span.section_id] = "\n".join(content_lines)
        result.update(_collect_all(span.children, lines))
    return result


def extract_all_sections(text: str) -> dict[str, str]:
    """Extract all sections from text, returning {section_id: content}.

    Parent sections include child markers in their content.
    Child sections return only their own content.
    """
    lines = text.splitlines()
    top_level, _ = _parse_spans(text)

    def _collect(spans: list[_SectionSpan]) -> dict[str, str]:
        result: dict[str, str] = {}
        for span in spans:
            if span.end_line is None:
                continue
            content_lines = lines[span.start_line + 1 : span.end_line]
            result[span.section_id] = "\n".join(content_lines)
            result.update(_collect(span.children))
        return result

    return _collect(top_level)


def extract_section(text: str, section_id: str) -> str | None:
    """Extract a single named section. Returns None if not found."""
    sections = extract_all_sections(text)
    return sections.get(section_id)


def extract_document_context_from_index(index_text: str) -> dict[str, object]:
    title: str | None = None
    overview_lines: list[str] = []
    caveats: list[str] = []
    in_overview = False

    for line in index_text.splitlines():
        stripped = line.strip()
        if title is None and stripped.startswith("# "):
            title = stripped.lstrip("#").strip()
            continue
        if stripped.startswith("|"):
            break
        if stripped.startswith(">"):
            value = stripped.lstrip(">").strip()
            if not value or value == AUTO_GENERATED_INDEX_NOTICE:
                continue
            overview_lines.append(value)
            in_overview = True
            continue
        if in_overview:
            break

    if not title:
        caveats.append("document title missing from companion index")
    overview = " ".join(overview_lines).strip()
    if len(overview) > DOCUMENT_OVERVIEW_LIMIT:
        overview = overview[:DOCUMENT_OVERVIEW_LIMIT].rstrip() + "…"
    if not overview:
        caveats.append("document overview missing from companion index")

    return {
        "title": title,
        "overview": overview or None,
        "caveats": caveats,
    }


def list_section_ids(text: str) -> list[str]:
    """List all section IDs in document order."""
    lines = text.splitlines()
    fenced = _skip_fenced_blocks(lines)
    ids: list[str] = []
    for i, line in enumerate(lines):
        if i in fenced:
            continue
        m = OPEN_RE.match(line.strip())
        if m:
            ids.append(m.group(1))
    return ids


def validate_section_markers(text: str) -> list[str]:
    """Validate section markers, returning a list of error messages (empty = valid)."""
    _, errors = _parse_spans(text)
    return errors


def _parse_wikilink(raw: str) -> tuple[str, str | None, str]:
    """Parse the inside of a [[...]] into (page, target_section_id, edge_type).

    Supports an optional typed prefix ([[type: target]]), an optional Obsidian-style
    display alias ([[target|alias]]), and an optional section anchor ([[page#section]]
    / [[page]] / [[#section]]). An empty page means a same-page link; a missing anchor
    means target_section_id is None. A bare link (no recognized "type: " prefix) gets
    edge_type "see-also"; an unrecognized prefix is returned verbatim for the caller to
    flag.
    """
    inner = raw.strip()
    type_match = EDGE_TYPE_RE.match(inner)
    if type_match:
        edge_type = type_match.group(1)
        rest = type_match.group(2).strip()
    else:
        edge_type = DEFAULT_EDGE_TYPE
        rest = inner
    target = rest.split("|", 1)[0].strip()
    page, _, section = target.partition("#")
    return page.strip(), (section.strip() or None), edge_type


def _innermost_section_at(spans: list[_SectionSpan], line: int) -> str | None:
    """Return the deepest section id whose content range strictly contains ``line``."""
    for span in spans:
        if span.end_line is None:
            continue
        if span.start_line < line < span.end_line:
            return _innermost_section_at(span.children, line) or span.section_id
    return None


def extract_section_links(text: str) -> dict[str, list[tuple[str, str | None, str]]]:
    """Map each section id to the [[page#section]] knowledge edges declared inside it.

    Each [[...]] is attributed to the innermost enclosing section (so a link in a
    child section is not double-counted on its parent). Links in fenced code blocks
    and inline code spans are ignored, and links outside any section are dropped
    (edges are section-to-section). Each edge is (page, target_section, edge_type);
    page="" denotes a same-page link.
    """
    lines = text.splitlines()
    fenced = _skip_fenced_blocks(lines)
    top_level, _ = _parse_spans(text)
    result: dict[str, list[tuple[str, str | None, str]]] = {}

    for i, line in enumerate(lines):
        if i in fenced:
            continue
        section_id = _innermost_section_at(top_level, i)
        if section_id is None:
            continue
        scrubbed = INLINE_CODE_RE.sub("", line)
        for match in WIKILINK_RE.finditer(scrubbed):
            page, target_section, edge_type = _parse_wikilink(match.group(1))
            result.setdefault(section_id, []).append((page, target_section, edge_type))

    return result
